window.exeSearchData = {"page-mpodm0mo-5t97mkx2k":{"name":"1. INICIO","isIndex":true,"fileName":"index.html","fileUrl":"index.html","prePageId":null,"nextPageId":"page-mpodm0mt-4lbldt0x0","blocks":{"block-1779373508146-38w2bflxb":{"name":"1. LET'S START","order":1,"idevices":{"idevice-1779373508144-gtdxty5ug":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <p>Hi everyone! </p>\n<p>We are starting a new Learning Situation called “Dealing with Peer Pressure.” In this link, you will find important information that you will need to understand how we are going to work through this Learning Situation. </p>\n<p><a href=\"https://view.genially.com/6a05d6570a485c0da8d6189b\" target=\"_blank\" title=\"\" rel=\"noopener\">Presentación en Genially</a></p>\n</div>","jsonProperties":"{\"ideviceId\":\"idevice-1779373508144-gtdxty5ug\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p>Hi everyone! </p>\\n<p>We are starting a new Learning Situation called “Dealing with Peer Pressure.” In this link, you will find important information that you will need to understand how we are going to work through this Learning Situation. </p>\\n<p><a href=\\\"https://view.genially.com/6a05d6570a485c0da8d6189b\\\" target=\\\"_blank\\\" title=\\\"\\\" rel=\\\"noopener\\\">Presentación en Genially</a></p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}},"page-mpodm0mt-4lbldt0x0":{"name":"2. LICENCIAS Y SEGURIDAD","isIndex":false,"fileName":"2-licencias-y-seguridad.html","fileUrl":"html/2-licencias-y-seguridad.html","prePageId":"page-mpodm0mo-5t97mkx2k","nextPageId":"page-mpodm0mv-1eratwgza","blocks":{"block-1779374369864-z7nzs31ql":{"name":"2. LICENSES & SAFETY","order":1,"idevices":{"idevice-1779374369862-sj840u7uw":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <p>Before we start, it is important to pay attention to some tips related to licenses and online safety.                                      Look carefully at this infographic and keep these advices in mind!</p>\n<figure class=\"exe-figure position-center\" style=\"width: 468px;\"><img src=\"{{context_path}}/content/resources/seguridad digital.jpg\" title=\"Infografía seguridad digital \" width=\"468\" height=\"1170\" alt=\"Infografía sobre seguridad y licencias digitales.\" />\n<figcaption class=\"figcaption\"><span class=\"license\"><span class=\"sep\">(</span><a href=\"http://creativecommons.org/publicdomain/zero/1.0/deed.en\" class=\"license\" target=\"_blank\" rel=\"noopener\">CC0</a><span class=\"sep\">)</span></span></figcaption>\n</figure>\n</div>","jsonProperties":"{\"ideviceId\":\"idevice-1779374369862-sj840u7uw\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p>Before we start, it is important to pay attention to some tips related to licenses and online safety.                                      Look carefully at this infographic and keep these advices in mind!</p>\\n<figure class=\\\"exe-figure position-center\\\" style=\\\"width: 468px;\\\"><img src=\\\"{{context_path}}/content/resources/seguridad digital.jpg\\\" title=\\\"Infografía seguridad digital \\\" width=\\\"468\\\" height=\\\"1170\\\" alt=\\\"Infografía sobre seguridad y licencias digitales.\\\" />\\n<figcaption class=\\\"figcaption\\\"><span class=\\\"license\\\"><span class=\\\"sep\\\">(</span><a href=\\\"http://creativecommons.org/publicdomain/zero/1.0/deed.en\\\" class=\\\"license\\\" target=\\\"_blank\\\" rel=\\\"noopener\\\">CC0</a><span class=\\\"sep\\\">)</span></span></figcaption>\\n</figure>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}},"page-mpodm0mv-1eratwgza":{"name":"3. HERRAMIENTA PARA EL PRODUCTO FINAL","isIndex":false,"fileName":"3-herramienta-para-el-producto-final.html","fileUrl":"html/3-herramienta-para-el-producto-final.html","prePageId":"page-mpodm0mt-4lbldt0x0","nextPageId":"page-mpodm0mx-k0h2nptik","blocks":{"block-1779375406123-gy45icw7t":{"name":"3. DIGITAL TOOL FOR THE FINAL PROJECT","order":1,"idevices":{"idevice-1779375406121-5mrrmie8a":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <p>The final project of this Learning Situation, entitled “Dealing with Peer Pressure,” consists of recording a trailer that will represent a situation involving bullying, cyberbullying, or discrimination. </p>\n<p>Among the video editing programs I have tested, <a href=\"https://clipchamp.com\" target=\"_blank\" title=\"\" rel=\"noopener\">Clipchamp</a> is the most suitable for you. It is an intuitive online application with a simple and visual interface that works directly from the browser, so no installation is required.</p>\n<p>With this tool, you can easily edit your videos by dragging and dropping elements, adding music, transitions, and effects. It also includes templates, automatic subtitles, and useful features for creating trailers. This tool allows you to create attractive results without advanced technical knowledge while also improving their digital skills.</p>\n</div>","jsonProperties":"{\"ideviceId\":\"idevice-1779375406121-5mrrmie8a\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p>The final project of this Learning Situation, entitled “Dealing with Peer Pressure,” consists of recording a trailer that will represent a situation involving bullying, cyberbullying, or discrimination. </p>\\n<p>Among the video editing programs I have tested, <a href=\\\"https://clipchamp.com\\\" target=\\\"_blank\\\" title=\\\"\\\" rel=\\\"noopener\\\">Clipchamp</a> is the most suitable for you. It is an intuitive online application with a simple and visual interface that works directly from the browser, so no installation is required.</p>\\n<p>With this tool, you can easily edit your videos by dragging and dropping elements, adding music, transitions, and effects. It also includes templates, automatic subtitles, and useful features for creating trailers. This tool allows you to create attractive results without advanced technical knowledge while also improving their digital skills.</p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}},"page-mpodm0mx-k0h2nptik":{"name":"4. HERRAMIENTAS PARA LA CURACIÓN DE CONTENIDO.","isIndex":false,"fileName":"4-herramientas-para-la-curacion-de-contenido.html","fileUrl":"html/4-herramientas-para-la-curacion-de-contenido.html","prePageId":"page-mpodm0mv-1eratwgza","nextPageId":"page-mpodm0mz-1h739hkky","blocks":{"block-1779376641179-uvbjgytfe":{"name":"USEFUL TOOLS AND RESOURCES FOR STUDENTS AND TEACHERS","order":1,"idevices":{"idevice-1779376641178-nw8wrfyf4":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <p>On the following subpages, students and teachers are provided with some useful resources to work independently.</p>\n</div>","jsonProperties":"{\"ideviceId\":\"idevice-1779376641178-nw8wrfyf4\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p>On the following subpages, students and teachers are provided with some useful resources to work independently.</p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}},"page-mpodm0mz-1h739hkky":{"name":"4.1. HERRAMIENTAS PARA EL ALUMNADO","isIndex":false,"fileName":"41-herramientas-para-el-alumnado.html","fileUrl":"html/41-herramientas-para-el-alumnado.html","prePageId":"page-mpodm0mx-k0h2nptik","nextPageId":"page-mpodm0n1-l6po3lnaq","blocks":{"block-1779376243974-twbd3czs8":{"name":"RESOURCES AND TOOLS FOR STUDENTS.","order":1,"idevices":{"idevice-1779376243973-pzz3zfoki":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <p>Dear students,</p>\n<p>In the following link you will find the<em> padlet</em> of the this learning situation with different resources and tools to help you not only create your final proyect, but also work through this unit. You will find five different categories: Grammar, (Cyber)bullying, Discrimination, Peer Pressure, and  Online Tools. Each category includes videos, websites and infographics that contain useful extra information about the topics we are working on. </p>\n<p><a href=\"https://padlet.com/isablgr/dealing-with-peer-pressure-u1xhf9656dcjrubx\" target=\"_blank\" title=\"\" rel=\"noopener\">Padlet </a></p>\n</div>","jsonProperties":"{\"ideviceId\":\"idevice-1779376243973-pzz3zfoki\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p>Dear students,</p>\\n<p>In the following link you will find the<em> padlet</em> of the this learning situation with different resources and tools to help you not only create your final proyect, but also work through this unit. You will find five different categories: Grammar, (Cyber)bullying, Discrimination, Peer Pressure, and  Online Tools. Each category includes videos, websites and infographics that contain useful extra information about the topics we are working on. </p>\\n<p><a href=\\\"https://padlet.com/isablgr/dealing-with-peer-pressure-u1xhf9656dcjrubx\\\" target=\\\"_blank\\\" title=\\\"\\\" rel=\\\"noopener\\\">Padlet </a></p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}},"page-mpodm0n1-l6po3lnaq":{"name":"4.2. HERRAMIENTAS PARA LOS DOCENTES","isIndex":false,"fileName":"42-herramientas-para-los-docentes.html","fileUrl":"html/42-herramientas-para-los-docentes.html","prePageId":"page-mpodm0mz-1h739hkky","nextPageId":"page-mpodm0n2-uth2qiyne","blocks":{"block-1779376358335-bdgdmh75o":{"name":"RESOURCES AND TOOLS FOR TEACHERS","order":1,"idevices":{"idevice-1779376358333-mgngef3a3":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <p>Dear teachers, </p>\n<p>In the following link, you will find my Symbaloo site, where I save and organize some of my favourite online resources and tools that support and enrich my teaching practice. </p>\n<p><a href=\"https://www.symbaloo.com/home/mix/13ePGfifJc\" title=\"\">Symbaloo</a></p>\n</div>","jsonProperties":"{\"ideviceId\":\"idevice-1779376358333-mgngef3a3\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p>Dear teachers, </p>\\n<p>In the following link, you will find my Symbaloo site, where I save and organize some of my favourite online resources and tools that support and enrich my teaching practice. </p>\\n<p><a href=\\\"https://www.symbaloo.com/home/mix/13ePGfifJc\\\" title=\\\"\\\">Symbaloo</a></p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}},"page-mpodm0n2-uth2qiyne":{"name":"5. GUÍA DIDÁCTICA","isIndex":false,"fileName":"5-guia-didactica.html","fileUrl":"html/5-guia-didactica.html","prePageId":"page-mpodm0n1-l6po3lnaq","nextPageId":"page-mpodm0n4-itnce01fx","blocks":{"block-1779379597296-kkkqhtq0h":{"name":"TEACHER'S GUIDE","order":1,"idevices":{"idevice-1779379597295-u4hstjtlg":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <p>The following link opens a Google Document containing the activities and tasks for this Learning Situation, along with their evaluation criteria, grouping, timing, and digital tools. </p>\n<p><br /></p>\n<p><a href=\"https://docs.google.com/document/d/10ewm-rxM4TEodmAzUllVWwonb1J2ujKq9QB8sZUp_ZY/edit?usp=sharing\" target=\"_blank\" rel=\"noopener\" title=\"\">Curricular specification</a></p>\n</div>","jsonProperties":"{\"ideviceId\":\"idevice-1779379597295-u4hstjtlg\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p>The following link opens a Google Document containing the activities and tasks for this Learning Situation, along with their evaluation criteria, grouping, timing, and digital tools. </p>\\n<p><br /></p>\\n<p><a href=\\\"https://docs.google.com/document/d/10ewm-rxM4TEodmAzUllVWwonb1J2ujKq9QB8sZUp_ZY/edit?usp=sharing\\\" target=\\\"_blank\\\" rel=\\\"noopener\\\" title=\\\"\\\">Curricular specification</a></p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}},"page-mpodm0n4-itnce01fx":{"name":"6. TEMPORALIZACIÓN","isIndex":false,"fileName":"6-temporalizacion.html","fileUrl":"html/6-temporalizacion.html","prePageId":"page-mpodm0n2-uth2qiyne","nextPageId":"page-mpodm0n6-pb662sdip","blocks":{"block-1779381897718-tfw6xeurp":{"name":"TIMELINE","order":1,"idevices":{"idevice-1779381897717-cqv7p6s6l":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <p style=\"text-align: justify;\">This Learning Situation follows a specific timeline of 11 sesions, each lasting 60 minutes. The infographic bellow shows the timeline for working through this Learning Situation. It also includes information about the tasks, grouping, and the materials and tools requiered by the students.  It is intended to be displayed in the classroom throughout the unit for the students to have a global vision of the unit and supports them with their own organization. </p>\n<figure class=\"exe-figure position-center\" style=\"width: 404px;\"><img src=\"{{context_path}}/content/resources/timeline(1).png\" title=\"Timeline\" width=\"404\" height=\"1010\" alt=\"Timeline of the Learning Situation\" />\n<figcaption class=\"figcaption\"><span class=\"license\"><span class=\"sep\">(</span><a href=\"http://creativecommons.org/publicdomain/zero/1.0/deed.en\" class=\"license\" target=\"_blank\" rel=\"noopener\">CC0</a><span class=\"sep\">)</span></span></figcaption>\n</figure>\n</div>","jsonProperties":"{\"ideviceId\":\"idevice-1779381897717-cqv7p6s6l\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p style=\\\"text-align: justify;\\\">This Learning Situation follows a specific timeline of 11 sesions, each lasting 60 minutes. The infographic bellow shows the timeline for working through this Learning Situation. It also includes information about the tasks, grouping, and the materials and tools requiered by the students.  It is intended to be displayed in the classroom throughout the unit for the students to have a global vision of the unit and supports them with their own organization. </p>\\n<figure class=\\\"exe-figure position-center\\\" style=\\\"width: 404px;\\\"><img src=\\\"{{context_path}}/content/resources/timeline(1).png\\\" title=\\\"Timeline\\\" width=\\\"404\\\" height=\\\"1010\\\" alt=\\\"Timeline of the Learning Situation\\\" />\\n<figcaption class=\\\"figcaption\\\"><span class=\\\"license\\\"><span class=\\\"sep\\\">(</span><a href=\\\"http://creativecommons.org/publicdomain/zero/1.0/deed.en\\\" class=\\\"license\\\" target=\\\"_blank\\\" rel=\\\"noopener\\\">CC0</a><span class=\\\"sep\\\">)</span></span></figcaption>\\n</figure>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}},"page-mpodm0n6-pb662sdip":{"name":"7. INSTRUMENTOS DE EVALUACIÓN","isIndex":false,"fileName":"7-instrumentos-de-evaluacion.html","fileUrl":"html/7-instrumentos-de-evaluacion.html","prePageId":"page-mpodm0n4-itnce01fx","nextPageId":"page-mpodm0n7-u4daeafyu","blocks":{"block-1779382909459-u8yuidve1":{"name":"ASSESSMENT INSTRUMENTS","order":1,"idevices":{"idevice-1779382909458-hnf7ulbw8":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <p>The final project of this Learning Situation is the creation of a trailer about a situacion of bullying, cyberbullying, or discrimination. I have chosen two different assessment instruments to evaluate the final projects: a rubric and a spider chart. The first one is intended for the teacher, while the second one is designed for peer assessment. </p>\n<p>To close the learning process of this learning situation, I have also included a third assessment instrument. In this case, it is a self-assessment Google Forms questionnaire for the students to evaluate their own work. </p>\n<p><br /></p>\n<p><br /></p>\n</div>","jsonProperties":"{\"ideviceId\":\"idevice-1779382909458-hnf7ulbw8\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p>The final project of this Learning Situation is the creation of a trailer about a situacion of bullying, cyberbullying, or discrimination. I have chosen two different assessment instruments to evaluate the final projects: a rubric and a spider chart. The first one is intended for the teacher, while the second one is designed for peer assessment. </p>\\n<p>To close the learning process of this learning situation, I have also included a third assessment instrument. In this case, it is a self-assessment Google Forms questionnaire for the students to evaluate their own work. </p>\\n<p><br /></p>\\n<p><br /></p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}},"page-mpodm0n7-u4daeafyu":{"name":"RÚBRICA DE EVALUACIÓN","isIndex":false,"fileName":"rubrica-de-evaluacion.html","fileUrl":"html/rubrica-de-evaluacion.html","prePageId":"page-mpodm0n6-pb662sdip","nextPageId":"page-mpodm0n9-uhlieqlvl","blocks":{"block-1779384285376-p5jj7kfcv":{"name":"ASSESSMENT RUBRIC","order":1,"idevices":{"idevice-1779384285375-pb9qttpjq":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <p>The final project of the Learning Situation I propose is the creation of a video in the form of a trailer about a situation of bullying, cyberbullying, or discrimination.</p>\n<p>As the project involves multiple competences—use of English, oral expression, creativity, digital competence, and social reflection—the rubric seems to me the most appropriate assessment instrument, as it allows all these aspects to be evaluated through specific criteria and well-defined performance levels. It is a very useful tool because it promotes objective and fair assessment.</p>\n<p><br /></p>\n<figure class=\"exe-figure position-center\" style=\"width: 800px;\"><img src=\"{{context_path}}/content/resources/Assessment rubric video cddb2 _page-0001.jpg\" width=\"800\" height=\"565\" alt=\"\" style=\"display: block; margin-left: auto; margin-right: auto;\" />\n<figcaption class=\"figcaption\"><span class=\"license\"><span class=\"sep\">(</span><a href=\"http://creativecommons.org/publicdomain/zero/1.0/deed.en\" class=\"license\" target=\"_blank\" rel=\"noopener\">CC0</a><span class=\"sep\">)</span></span></figcaption>\n</figure>\n</div>","jsonProperties":"{\"ideviceId\":\"idevice-1779384285375-pb9qttpjq\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p>The final project of the Learning Situation I propose is the creation of a video in the form of a trailer about a situation of bullying, cyberbullying, or discrimination.</p>\\n<p>As the project involves multiple competences—use of English, oral expression, creativity, digital competence, and social reflection—the rubric seems to me the most appropriate assessment instrument, as it allows all these aspects to be evaluated through specific criteria and well-defined performance levels. It is a very useful tool because it promotes objective and fair assessment.</p>\\n<p><br /></p>\\n<figure class=\\\"exe-figure position-center\\\" style=\\\"width: 800px;\\\"><img src=\\\"{{context_path}}/content/resources/Assessment rubric video cddb2 _page-0001.jpg\\\" width=\\\"800\\\" height=\\\"565\\\" alt=\\\"\\\" style=\\\"display: block; margin-left: auto; margin-right: auto;\\\" />\\n<figcaption class=\\\"figcaption\\\"><span class=\\\"license\\\"><span class=\\\"sep\\\">(</span><a href=\\\"http://creativecommons.org/publicdomain/zero/1.0/deed.en\\\" class=\\\"license\\\" target=\\\"_blank\\\" rel=\\\"noopener\\\">CC0</a><span class=\\\"sep\\\">)</span></span></figcaption>\\n</figure>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}},"page-mpodm0n9-uhlieqlvl":{"name":"COEVALUACIÓN","isIndex":false,"fileName":"coevaluacion.html","fileUrl":"html/coevaluacion.html","prePageId":"page-mpodm0n7-u4daeafyu","nextPageId":"page-mpodm0na-gunl8c47g","blocks":{"block-1779384018980-kte9gb93g":{"name":"PEER- ASSESSMENT","order":1,"idevices":{"idevice-1779384018978-zvz9vs6k8":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <p>After watching each trailer, students will assess the different projects using a spider chart. In this case, a poster with the spider chart will be displayed in the classroom after the video screening and students will evaluate it by placing an dot in each circle corresponding to a level of achievement. </p>\n<p>This type of assessment promotes peer assessment, encouraging critical thinking, as students visually and in a simple form evaluate different aspects of their classmates' work. By representing results graphically, students can easily identify their strengths and areas of improvement. </p>\n<p>Another important aspect of the assessment wheel is that it reduces the negative perception of assessment, as it is a dynamic and participatory process. </p>\n<p><br /></p>\n<figure class=\"exe-figure position-center\" style=\"width: 601px;\"><img src=\"{{context_path}}/content/resources/Kopie von SELF-ASSESSMENT SPIDER GRAPH.png\" title=\"Spider chart\" width=\"601\" height=\"850\" alt=\"Diana de evaluación\" />\n<figcaption class=\"figcaption\"><span class=\"license\"><span class=\"sep\">(</span><a href=\"http://creativecommons.org/publicdomain/zero/1.0/deed.en\" class=\"license\" target=\"_blank\" rel=\"noopener\">CC0</a><span class=\"sep\">)</span></span></figcaption>\n</figure>\n</div>","jsonProperties":"{\"ideviceId\":\"idevice-1779384018978-zvz9vs6k8\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p>After watching each trailer, students will assess the different projects using a spider chart. In this case, a poster with the spider chart will be displayed in the classroom after the video screening and students will evaluate it by placing an dot in each circle corresponding to a level of achievement. </p>\\n<p>This type of assessment promotes peer assessment, encouraging critical thinking, as students visually and in a simple form evaluate different aspects of their classmates' work. By representing results graphically, students can easily identify their strengths and areas of improvement. </p>\\n<p>Another important aspect of the assessment wheel is that it reduces the negative perception of assessment, as it is a dynamic and participatory process. </p>\\n<p><br /></p>\\n<figure class=\\\"exe-figure position-center\\\" style=\\\"width: 601px;\\\"><img src=\\\"{{context_path}}/content/resources/Kopie von SELF-ASSESSMENT SPIDER GRAPH.png\\\" title=\\\"Spider chart\\\" width=\\\"601\\\" height=\\\"850\\\" alt=\\\"Diana de evaluación\\\" />\\n<figcaption class=\\\"figcaption\\\"><span class=\\\"license\\\"><span class=\\\"sep\\\">(</span><a href=\\\"http://creativecommons.org/publicdomain/zero/1.0/deed.en\\\" class=\\\"license\\\" target=\\\"_blank\\\" rel=\\\"noopener\\\">CC0</a><span class=\\\"sep\\\">)</span></span></figcaption>\\n</figure>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}},"page-mpodm0na-gunl8c47g":{"name":"AUTOEVALUACIÓN","isIndex":false,"fileName":"autoevaluacion.html","fileUrl":"html/autoevaluacion.html","prePageId":"page-mpodm0n9-uhlieqlvl","nextPageId":"page-mpodm0nb-uvjmxgpo9","blocks":{"block-1779383862304-fkbvhkj8b":{"name":"SELF-ASSESSMENT","order":1,"idevices":{"idevice-1779383862302-311sox0dt":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <p>At the end of the Learning Situation, students will complete a digital questionnarie created with Google Forms to evaluate their participation and learning process throught the Learning Situation. Self-assessment encourages critical reflection on their performance, autonomy, and responsability. </p>\n<p><a href=\"https://docs.google.com/forms/d/e/1FAIpQLSd9QnlOPia1LnB9K10AnsIzhGilaLaKNHxwSu2USv5NDK436A/viewform?usp=publish-editor\" target=\"_blank\" title=\"\" rel=\"noopener\">Questionnaire</a></p>\n</div>","jsonProperties":"{\"ideviceId\":\"idevice-1779383862302-311sox0dt\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p>At the end of the Learning Situation, students will complete a digital questionnarie created with Google Forms to evaluate their participation and learning process throught the Learning Situation. Self-assessment encourages critical reflection on their performance, autonomy, and responsability. </p>\\n<p><a href=\\\"https://docs.google.com/forms/d/e/1FAIpQLSd9QnlOPia1LnB9K10AnsIzhGilaLaKNHxwSu2USv5NDK436A/viewform?usp=publish-editor\\\" target=\\\"_blank\\\" title=\\\"\\\" rel=\\\"noopener\\\">Questionnaire</a></p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}},"page-mpodm0nb-uvjmxgpo9":{"name":"8. CRÉDITOS","isIndex":false,"fileName":"8-creditos.html","fileUrl":"html/8-creditos.html","prePageId":"page-mpodm0na-gunl8c47g","nextPageId":null,"blocks":{"block-1779401930528-tcztujc15":{"name":"Credits","order":1,"idevices":{"idevice-1779401930526-0i1h7cibb":{"order":1,"htmlView":"<div class=\"exe-download-package-instructions\"><table class=\"exe-table exe-package-info\"><caption>General information about this educational resource</caption>\n<tbody>\n<tr>\n<th>Title</th>\n<td class=\"mceNonEditable exe-prop-locked\"><span class=\"exe-prop-title\">Dealing with Peer Pressue</span></td>\n</tr>\n<tr>\n<th>Description</th>\n<td class=\"mceNonEditable exe-prop-locked\"><span class=\"exe-prop-description\">El presente proyecto ha sido elaborado como producto final del CDD B2 de la Junta de Andalucía. \nEstán incluidas todas las tareas que se han ido realizando a lo largo de cada uno de los módulos que completan el curso. </span></td>\n</tr>\n<tr>\n<th>Authorship</th>\n<td class=\"mceNonEditable exe-prop-locked\"><span class=\"exe-prop-author\">Isabel García Ruiz</span></td>\n</tr>\n<tr>\n<th>License</th>\n<td class=\"mceNonEditable exe-prop-locked\"><span class=\"exe-prop-license\">creative commons: attribution - share alike 4.0</span></td>\n</tr>\n</tbody>\n</table>\n<p style=\"text-align: center;\">This content was created with <a href=\"https://exelearning.net/\">eXeLearning</a>, your free and open source editor to create educational resources.</p></div><p class=\"exe-download-package-link\"><a download=\"exe-package:elp-name\" href=\"exe-package:elp\" style=\"background-color:#107275;color:#ffffff;\">Download .elpx file</a></p>","jsonProperties":"{}"}}}}}};